class Solution:
    def primeSubOperation(self, nums):
        LIMIT = 1000
        sieve = [True] * (LIMIT + 1)
        sieve[0] = sieve[1] = False
        for i in range(2, int(LIMIT ** 0.5) + 1):
            if sieve[i]:
                for j in range(i * i, LIMIT + 1, i):
                    sieve[j] = False
        reachable = {0}
        for x in nums:
            nxt = set()
            for prev in reachable:
                if x > prev:
                    nxt.add(x)
                for p in range(2, x):
                    if sieve[p] and (x - p) > prev:
                        nxt.add(x - p)
            if not nxt:
                return False
            reachable = nxt
        return True

