import bisect
class Solution:
    def primeSubOperation(self, nums):
        LIMIT = 1000
        sieve = [True] * (LIMIT + 1)
        sieve[0] = sieve[1] = False
        for i in range(2, int(LIMIT ** 0.5) + 1):
            if sieve[i]:
                for j in range(i * i, LIMIT + 1, i):
                    sieve[j] = False
        primes = [i for i in range(2, LIMIT + 1) if sieve[i]]
        prev = 0
        for x in nums:
            bound = min(x - 1, x - prev - 1)
            chosen_p = 0
            if bound >= 2:
                idx = bisect.bisect_right(primes, bound) - 1
                if idx >= 0:
                    chosen_p = primes[idx]
            new_val = x - chosen_p
            if new_val > prev:
                prev = new_val
            else:
                return False
        return True

