var primeSubOperation = function(nums) {
    const LIMIT = 1000;
    const sieve = new Array(LIMIT + 1).fill(true);
    sieve[0] = sieve[1] = false;
    for (let i = 2; i * i <= LIMIT; i++) {
        if (sieve[i]) {
            for (let j = i * i; j <= LIMIT; j += i) sieve[j] = false;
        }
    }
    const primes = [];
    for (let i = 2; i <= LIMIT; i++) if (sieve[i]) primes.push(i);
    let prev = 0;
    for (const x of nums) {
        const bound = Math.min(x - 1, x - prev - 1);
        let chosenP = 0;
        if (bound >= 2) {
            let lo = 0, hi = primes.length;
            while (lo < hi) {
                const mid = (lo + hi) >> 1;
                if (primes[mid] <= bound) lo = mid + 1; else hi = mid;
            }
            if (lo - 1 >= 0) chosenP = primes[lo - 1];
        }
        const newVal = x - chosenP;
        if (newVal > prev) {
            prev = newVal;
        } else {
            return false;
        }
    }
    return true;
};
